// Normaliza el mensaje recibido y extrae los campos clave.
const msg = $input.first().json.message;
const telegram_user = String(msg.from.id);
const nombre_telegram = (msg.from.first_name || '') + (msg.from.last_name ? ' ' + msg.from.last_name : '');
const texto = (msg.text || '').trim();
const esComando = texto.startsWith('/');
const comando = esComando ? texto.split(' ')[0].toLowerCase() : '';

return [{
  json: {
    telegram_user,
    nombre_telegram,
    texto,
    esComando,
    comando,
    chat_id: msg.chat.id
  }
}];

// Verifica si el usuario existe y está activo.
// Trae también la entrada original.
const entrada = $('Normalizar Input').first().json;
const usuarios = $input.all();
const usuario = usuarios.length > 0 ? usuarios[0].json : null;

let estado;
if (!usuario || Object.keys(usuario).length === 0) {
  estado = 'NO_REGISTRADO';
} else if (String(usuario.activo).toUpperCase() === 'TRUE' || usuario.activo === true) {
  estado = 'ACTIVO';
} else {
  estado = 'INACTIVO';
}

return [{
  json: {
    ...entrada,
    usuario_estado: estado,
    usuario_nombre: usuario ? usuario.nombre : entrada.nombre_telegram,
    usuario_rol: usuario ? usuario.rol : 'usuario'
  }
}];

// ============================================================
// MOTOR CONVERSACIONAL - HELPDESKBOT
// Decide la siguiente pantalla y arma la respuesta
// ============================================================
const entrada = $('Validar Usuario Activo').first().json;
const sesiones = $input.all();
const sesionActual = (sesiones.length > 0 && Object.keys(sesiones[0].json).length > 0) ? sesiones[0].json : null;

const pantalla = sesionActual ? (sesionActual.pantalla_actual || 'MENU_PRINCIPAL') : 'MENU_PRINCIPAL';
let datos = {};
try {
  datos = sesionActual && sesionActual.datos_temporales ? JSON.parse(sesionActual.datos_temporales) : {};
} catch (e) {
  datos = {};
}

const texto = entrada.texto;
const esComando = entrada.esComando;
const comando = entrada.comando;

// ----------- HELPERS DE MENSAJES -----------
const MSG_BIENVENIDA = `Hola, soy HelpDeskBot 👋\n\nEstoy aquí para ayudarte con solicitudes de soporte\nde forma rápida y ordenada.\n\nPor favor escribe el número de la opción que quieras usar.\n\nMenú principal:\n0. Ayuda\n1. Crear solicitud\n2. Consultar estado de solicitud\n3. Mis solicitudes\n4. Reportes\n5. Configuración`;

const MSG_AYUDA = `ℹ️ Ayuda\n\nEnvía el número de la opción que quieras usar.\nEn cualquier menú puedes escribir 9 para cancelar.\nUsa /start si te pierdes y quieres volver al inicio.`;

const MSG_TIPO = `Vamos a crear una solicitud, para lo cual se necesitará de escoger su tipo.\n\nSelecciona el tipo:\n1. Soporte técnico\n2. Solicitud administrativa\n3. Consulta general\n9. Cancelar`;

const MSG_PRIORIDAD = `¿Qué tan urgente es tu solicitud?\n\n1. Alta\n2. Media\n3. Baja\n9. Cancelar`;

const MSG_DESCRIPCION = `Por favor describe brevemente tu solicitud.\n(Mínimo 10 caracteres, máximo 500.)\n\nEscribe "cancelar" si deseas abortar.`;

const confirmacionMsg = (d) => `Por favor revisa los datos de tu solicitud:\n\nTipo: ${d.tipo}\nPrioridad: ${d.prioridad}\nDescripción: ${d.descripcion}\n\n1. Confirmar y registrar\n9. Cancelar`;

// ----------- COMANDOS GLOBALES -----------
// /start o /menu fuerzan el regreso al menú principal
if (esComando && (comando === '/start' || comando === '/menu' || comando === '/inicio')) {
  return [{
    json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id,
      telegram_user: entrada.telegram_user,
      mensaje: MSG_BIENVENIDA,
      nueva_pantalla: 'MENU_PRINCIPAL',
      nuevos_datos: '{}',
      log_pantalla: pantalla,
      log_opcion: texto,
      log_resultado: 'OK'
    }
  }];
}

if (esComando && comando === '/ayuda') {
  return [{
    json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id,
      telegram_user: entrada.telegram_user,
      mensaje: MSG_AYUDA,
      nueva_pantalla: 'MENU_PRINCIPAL',
      nuevos_datos: '{}',
      log_pantalla: pantalla,
      log_opcion: texto,
      log_resultado: 'OK'
    }
  }];
}

// Cancelación universal en cualquier pantalla del wizard
if (texto === '9' || texto.toLowerCase() === 'cancelar') {
  if (pantalla.startsWith('CREAR_') || pantalla === 'CONSULTAR_TICKET') {
    return [{
      json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id,
        telegram_user: entrada.telegram_user,
        mensaje: '❌ Operación cancelada.\n\n' + MSG_BIENVENIDA,
        nueva_pantalla: 'MENU_PRINCIPAL',
        nuevos_datos: '{}',
        log_pantalla: pantalla,
        log_opcion: texto,
        log_resultado: 'CANCELADO'
      }
    }];
  }
}

// ----------- MÁQUINA DE ESTADOS -----------

// PANTALLA: MENU_PRINCIPAL
if (pantalla === 'MENU_PRINCIPAL') {
  switch (texto) {
    case '0':
      return [{ json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        mensaje: MSG_AYUDA, nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    case '1':
      return [{ json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        mensaje: MSG_TIPO, nueva_pantalla: 'CREAR_TIPO', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    case '2':
      return [{ json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        mensaje: 'Por favor envíame el ID del ticket (formato HD-YYYYMMDD-NNNN):',
        nueva_pantalla: 'CONSULTAR_TICKET', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    case '3':
      return [{ json: {
        accion: 'LISTAR_MIS_SOLICITUDES',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    case '4':
      return [{ json: {
        accion: 'GENERAR_REPORTE',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    case '5':
      return [{ json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        mensaje: `⚙️ Configuración\n\nUsuario: ${entrada.usuario_nombre}\nRol: ${entrada.usuario_rol}\n\nLa edición de configuración se realiza desde el panel administrativo.\n\nEnvía /start para volver al menú.`,
        nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
      }}];
    default:
      return [{ json: {
        accion: 'RESPONDER_Y_GUARDAR_SESION',
        chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
        mensaje: '⚠️ Opción no reconocida.\n\n' + MSG_BIENVENIDA,
        nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
        log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_VALIDACION'
      }}];
  }
}

// PANTALLA: CREAR_TIPO
if (pantalla === 'CREAR_TIPO') {
  const tipos = { '1': 'Soporte técnico', '2': 'Solicitud administrativa', '3': 'Consulta general' };
  if (tipos[texto]) {
    datos.tipo = tipos[texto];
    return [{ json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
      mensaje: MSG_PRIORIDAD, nueva_pantalla: 'CREAR_PRIORIDAD',
      nuevos_datos: JSON.stringify(datos),
      log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
    }}];
  }
  return [{ json: {
    accion: 'RESPONDER_Y_GUARDAR_SESION',
    chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
    mensaje: '⚠️ Opción inválida.\n\n' + MSG_TIPO,
    nueva_pantalla: 'CREAR_TIPO', nuevos_datos: JSON.stringify(datos),
    log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_VALIDACION'
  }}];
}

// PANTALLA: CREAR_PRIORIDAD
if (pantalla === 'CREAR_PRIORIDAD') {
  const prioridades = { '1': 'Alta', '2': 'Media', '3': 'Baja' };
  if (prioridades[texto]) {
    datos.prioridad = prioridades[texto];
    return [{ json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
      mensaje: MSG_DESCRIPCION, nueva_pantalla: 'CREAR_DESCRIPCION',
      nuevos_datos: JSON.stringify(datos),
      log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
    }}];
  }
  return [{ json: {
    accion: 'RESPONDER_Y_GUARDAR_SESION',
    chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
    mensaje: '⚠️ Prioridad inválida.\n\n' + MSG_PRIORIDAD,
    nueva_pantalla: 'CREAR_PRIORIDAD', nuevos_datos: JSON.stringify(datos),
    log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_VALIDACION'
  }}];
}

// PANTALLA: CREAR_DESCRIPCION
if (pantalla === 'CREAR_DESCRIPCION') {
  const descripcion = texto;
  if (descripcion.length < 10 || descripcion.length > 500) {
    return [{ json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
      mensaje: `⚠️ La descripción debe tener entre 10 y 500 caracteres (recibí ${descripcion.length}).\n\n${MSG_DESCRIPCION}`,
      nueva_pantalla: 'CREAR_DESCRIPCION', nuevos_datos: JSON.stringify(datos),
      log_pantalla: pantalla, log_opcion: '<descripcion>', log_resultado: 'ERROR_VALIDACION'
    }}];
  }
  datos.descripcion = descripcion;
  return [{ json: {
    accion: 'RESPONDER_Y_GUARDAR_SESION',
    chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
    mensaje: confirmacionMsg(datos),
    nueva_pantalla: 'CREAR_CONFIRMACION', nuevos_datos: JSON.stringify(datos),
    log_pantalla: pantalla, log_opcion: '<descripcion>', log_resultado: 'OK'
  }}];
}

// PANTALLA: CREAR_CONFIRMACION
if (pantalla === 'CREAR_CONFIRMACION') {
  if (texto === '1') {
    return [{ json: {
      accion: 'GUARDAR_TICKET',
      chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
      datos_ticket: datos,
      nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
      log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
    }}];
  }
  return [{ json: {
    accion: 'RESPONDER_Y_GUARDAR_SESION',
    chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
    mensaje: '⚠️ Opción inválida. Responde 1 para confirmar o 9 para cancelar.\n\n' + confirmacionMsg(datos),
    nueva_pantalla: 'CREAR_CONFIRMACION', nuevos_datos: JSON.stringify(datos),
    log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_VALIDACION'
  }}];
}

// PANTALLA: CONSULTAR_TICKET
if (pantalla === 'CONSULTAR_TICKET') {
  const idTicket = texto.toUpperCase();
  if (!/^HD-\d{8}-\d{4}$/.test(idTicket)) {
    return [{ json: {
      accion: 'RESPONDER_Y_GUARDAR_SESION',
      chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
      mensaje: '⚠️ Formato inválido. El ID debe ser tipo HD-20260427-0034.\n\nEscribe 9 para cancelar.',
      nueva_pantalla: 'CONSULTAR_TICKET', nuevos_datos: '{}',
      log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_VALIDACION'
    }}];
  }
  return [{ json: {
    accion: 'CONSULTAR_TICKET',
    chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
    id_ticket: idTicket,
    nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
    log_pantalla: pantalla, log_opcion: texto, log_resultado: 'OK'
  }}];
}

// FALLBACK
return [{ json: {
  accion: 'RESPONDER_Y_GUARDAR_SESION',
  chat_id: entrada.chat_id, telegram_user: entrada.telegram_user,
  mensaje: MSG_BIENVENIDA, nueva_pantalla: 'MENU_PRINCIPAL', nuevos_datos: '{}',
  log_pantalla: pantalla, log_opcion: texto, log_resultado: 'ERROR_SISTEMA'
}}];

// Genera el id_ticket consecutivo del día
const datos = $('Motor Conversacional').first().json;
const entrada = $('Validar Usuario Activo').first().json;
const solicitudes = $input.all().map(i => i.json);

const hoy = new Date();
const yyyy = hoy.getFullYear();
const mm = String(hoy.getMonth() + 1).padStart(2, '0');
const dd = String(hoy.getDate()).padStart(2, '0');
const fechaStr = `${yyyy}${mm}${dd}`;

// Contar tickets del día actual
const delDia = solicitudes.filter(s => s.id_ticket && s.id_ticket.startsWith(`HD-${fechaStr}`));
const consecutivo = String(delDia.length + 1).padStart(4, '0');
const idTicket = `HD-${fechaStr}-${consecutivo}`;

const fechaCreacion = hoy.toISOString();

return [{
  json: {
    id_ticket: idTicket,
    tipo: datos.datos_ticket.tipo,
    prioridad: datos.datos_ticket.prioridad,
    descripcion: datos.datos_ticket.descripcion,
    estado: 'Abierto',
    creado_por: entrada.telegram_user,
    fecha_creacion: fechaCreacion,
    chat_id: datos.chat_id,
    telegram_user: datos.telegram_user,
    log_pantalla: datos.log_pantalla,
    log_opcion: datos.log_opcion,
    log_resultado: datos.log_resultado,
    nueva_pantalla: datos.nueva_pantalla,
    nuevos_datos: datos.nuevos_datos
  }
}];

// Construye el mensaje de éxito y propaga el contexto
const t = $input.first().json;
const mensaje = `✅ Solicitud registrada con éxito.\n\nID: ${t.id_ticket}\nEstado: ${t.estado}\n\nTe notificaremos cuando haya cambios.\n\nEscribe /start para volver al menú principal.`;
return [{
  json: {
    chat_id: t.chat_id,
    telegram_user: t.telegram_user,
    mensaje,
    nueva_pantalla: 'MENU_PRINCIPAL',
    nuevos_datos: '{}',
    log_pantalla: t.log_pantalla,
    log_opcion: t.log_opcion,
    log_resultado: t.log_resultado
  }
}];

// Formatea la respuesta de consulta de ticket
const datos = $('Motor Conversacional').first().json;
const resultados = $input.all();
const ticket = (resultados.length > 0 && Object.keys(resultados[0].json).length > 0) ? resultados[0].json : null;

let mensaje;
if (!ticket) {
  mensaje = `❌ No se encontró el ticket ${datos.id_ticket}.\n\nVerifica el ID e intenta de nuevo.\nEscribe /start para volver al menú.`;
} else {
  mensaje = `🎫 Ticket ${ticket.id_ticket}\n\nTipo: ${ticket.tipo}\nPrioridad: ${ticket.prioridad}\nEstado: ${ticket.estado}\nCreado: ${ticket.fecha_creacion}\n\nDescripción: ${ticket.descripcion}\n\nEscribe /start para volver al menú.`;
}

return [{
  json: {
    chat_id: datos.chat_id,
    telegram_user: datos.telegram_user,
    mensaje,
    nueva_pantalla: 'MENU_PRINCIPAL',
    nuevos_datos: '{}',
    log_pantalla: datos.log_pantalla,
    log_opcion: datos.log_opcion,
    log_resultado: ticket ? 'OK' : 'ERROR_VALIDACION'
  }
}];

// Filtra los tickets del usuario y arma listado
const datos = $('Motor Conversacional').first().json;
const todos = $input.all().map(i => i.json);
const mios = todos.filter(t => String(t.creado_por) === String(datos.telegram_user));

let mensaje;
if (mios.length === 0) {
  mensaje = `📋 No tienes solicitudes registradas.\n\nEscribe /start para volver al menú.`;
} else {
  // Ordenar más recientes primero
  mios.sort((a, b) => (b.fecha_creacion || '').localeCompare(a.fecha_creacion || ''));
  const lineas = mios.slice(0, 10).map(t => `• ${t.id_ticket} [${t.estado}] ${t.tipo} - ${t.prioridad}`);
  mensaje = `📋 Tus solicitudes (últimas ${Math.min(mios.length, 10)}):\n\n${lineas.join('\n')}\n\nEscribe /start para volver al menú.`;
}

return [{
  json: {
    chat_id: datos.chat_id,
    telegram_user: datos.telegram_user,
    mensaje,
    nueva_pantalla: 'MENU_PRINCIPAL',
    nuevos_datos: '{}',
    log_pantalla: datos.log_pantalla,
    log_opcion: datos.log_opcion,
    log_resultado: 'OK'
  }
}];

// Genera reporte agrupado por estado y tipo
const datos = $('Motor Conversacional').first().json;
const todos = $input.all().map(i => i.json).filter(t => t.id_ticket);

const porEstado = {};
const porTipo = {};
const porPrioridad = {};

todos.forEach(t => {
  porEstado[t.estado] = (porEstado[t.estado] || 0) + 1;
  porTipo[t.tipo] = (porTipo[t.tipo] || 0) + 1;
  porPrioridad[t.prioridad] = (porPrioridad[t.prioridad] || 0) + 1;
});

const formatGrupo = (obj) => Object.entries(obj).map(([k, v]) => `  • ${k}: ${v}`).join('\n') || '  (sin datos)';

const mensaje = `📊 Reporte de solicitudes\n\nTotal: ${todos.length}\n\nPor estado:\n${formatGrupo(porEstado)}\n\nPor tipo:\n${formatGrupo(porTipo)}\n\nPor prioridad:\n${formatGrupo(porPrioridad)}\n\nEscribe /start para volver al menú.`;

return [{
  json: {
    chat_id: datos.chat_id,
    telegram_user: datos.telegram_user,
    mensaje,
    nueva_pantalla: 'MENU_PRINCIPAL',
    nuevos_datos: '{}',
    log_pantalla: datos.log_pantalla,
    log_opcion: datos.log_opcion,
    log_resultado: 'OK'
  }
}];
